<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    :root {
      color-scheme: light;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background: #f3f5f8;
      color: #1f2937;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      padding: 24px;
    }

    .app {
      width: min(900px, 100%);
      margin: 0 auto;
    }

    h1, h2 {
      margin-top: 0;
    }

    .panel {
      margin-bottom: 20px;
      padding: 20px;
      border: 1px solid #d9dee7;
      border-radius: 10px;
      background: #fff;
      box-shadow: 0 2px 8px rgba(31, 41, 55, 0.05);
    }

    .form-grid,
    .filter-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 14px;
    }

    label {
      display: flex;
      flex-direction: column;
      gap: 6px;
      font-weight: 600;
    }

    input,
    select,
    button {
      min-height: 42px;
      border: 1px solid #b8c0cc;
      border-radius: 6px;
      font: inherit;
    }

    input,
    select {
      width: 100%;
      padding: 8px 10px;
      background: #fff;
      color: #1f2937;
    }

    button {
      padding: 9px 16px;
      border-color: #2563eb;
      background: #2563eb;
      color: #fff;
      font-weight: 700;
      cursor: pointer;
    }

    button:hover {
      background: #1d4ed8;
    }

    #add-expense {
      align-self: end;
    }

    #form-error {
      min-height: 24px;
      margin: 10px 0 0;
      color: #b91c1c;
      font-weight: 600;
    }

    .summary {
      display: grid;
      grid-template-columns: repeat(5, minmax(0, 1fr));
      gap: 10px;
    }

    .summary-card {
      padding: 14px;
      border-radius: 8px;
      background: #eef2ff;
      text-align: center;
    }

    .summary-card strong {
      display: block;
      margin-top: 4px;
      font-size: 1.15rem;
    }

    .list-header,
    .expense {
      display: grid;
      grid-template-columns: 1fr 1fr 1fr 1.5fr auto;
      gap: 12px;
      align-items: center;
    }

    .list-header {
      padding: 0 12px 9px;
      border-bottom: 2px solid #d9dee7;
      color: #4b5563;
      font-weight: 700;
    }

    .expense {
      padding: 12px;
      border-bottom: 1px solid #e5e7eb;
    }

    .expense:last-child {
      border-bottom: 0;
    }

    .amount-cell {
      font-weight: 700;
    }

    .category-cell {
      text-transform: capitalize;
    }

    .note-cell {
      overflow-wrap: anywhere;
      color: #4b5563;
    }

    .exp-del {
      min-height: 34px;
      padding: 6px 11px;
      border-color: #dc2626;
      background: #dc2626;
    }

    .exp-del:hover {
      background: #b91c1c;
    }

    #empty-message {
      margin: 18px 0 0;
      color: #6b7280;
      text-align: center;
    }

    [hidden] {
      display: none !important;
    }

    @media (max-width: 700px) {
      body {
        padding: 12px;
      }

      .form-grid,
      .filter-grid,
      .summary {
        grid-template-columns: 1fr;
      }

      .list-header {
        display: none;
      }

      .expense {
        grid-template-columns: 1fr auto;
      }

      .expense span {
        grid-column: 1;
      }

      .exp-del {
        grid-column: 2;
        grid-row: 1 / span 4;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <h1>Personal Expense Tracker</h1>

    <section class="panel" aria-labelledby="entry-heading">
      <h2 id="entry-heading">Add an expense</h2>
      <form id="expense-form" novalidate>
        <div class="form-grid">
          <label>
            Amount
            <input id="amount" type="number" step="any" placeholder="0.00">
          </label>

          <label>
            Category
            <select id="category">
              <option value="groceries">Groceries</option>
              <option value="transport">Transport</option>
              <option value="bills">Bills</option>
              <option value="fun">Fun</option>
            </select>
          </label>

          <label>
            Date
            <input id="date" type="date">
          </label>

          <label>
            Note (optional)
            <input id="note" type="text" maxlength="200" placeholder="What was this for?">
          </label>

          <button id="add-expense" type="submit">Add expense</button>
        </div>
        <p id="form-error" role="alert" aria-live="polite"></p>
      </form>
    </section>

    <section class="panel" aria-labelledby="filters-heading">
      <h2 id="filters-heading">Filters</h2>
      <div class="filter-grid">
        <label>
          Category
          <select id="filter-category">
            <option value="all">All categories</option>
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </label>

        <label>
          From
          <input id="filter-from" type="date">
        </label>

        <label>
          To
          <input id="filter-to" type="date">
        </label>
      </div>
    </section>

    <section class="panel" aria-labelledby="summary-heading">
      <h2 id="summary-heading">Visible totals</h2>
      <div class="summary">
        <div class="summary-card">
          Total
          <strong id="total">0.00</strong>
        </div>
        <div class="summary-card cat-total" data-cat="groceries">
          Groceries
          <strong>0.00</strong>
        </div>
        <div class="summary-card cat-total" data-cat="transport">
          Transport
          <strong>0.00</strong>
        </div>
        <div class="summary-card cat-total" data-cat="bills">
          Bills
          <strong>0.00</strong>
        </div>
        <div class="summary-card cat-total" data-cat="fun">
          Fun
          <strong>0.00</strong>
        </div>
      </div>
    </section>

    <section class="panel" aria-labelledby="expenses-heading">
      <h2 id="expenses-heading">Expenses</h2>
      <div class="list-header" aria-hidden="true">
        <span>Amount</span>
        <span>Category</span>
        <span>Date</span>
        <span>Note</span>
        <span>Action</span>
      </div>
      <div id="expense-list"></div>
      <p id="empty-message">No expenses yet.</p>
    </section>
  </main>

  <script>
    (() => {
      "use strict";

      const STORAGE_KEY = "personal-expense-tracker-expenses";
      const categories = ["groceries", "transport", "bills", "fun"];

      const form = document.getElementById("expense-form");
      const amountInput = document.getElementById("amount");
      const categoryInput = document.getElementById("category");
      const dateInput = document.getElementById("date");
      const noteInput = document.getElementById("note");
      const formError = document.getElementById("form-error");
      const list = document.getElementById("expense-list");
      const totalElement = document.getElementById("total");
      const emptyMessage = document.getElementById("empty-message");

      const filterCategory = document.getElementById("filter-category");
      const filterFrom = document.getElementById("filter-from");
      const filterTo = document.getElementById("filter-to");

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          if (!Array.isArray(saved)) return [];

          return saved.filter(expense =>
            expense &&
            Number.isFinite(Number(expense.amount)) &&
            Number(expense.amount) > 0 &&
            categories.includes(expense.category) &&
            typeof expense.date === "string" &&
            expense.date.length > 0
          ).map(expense => ({
            id: String(expense.id || createId()),
            amount: Number(expense.amount),
            category: expense.category,
            date: expense.date,
            note: typeof expense.note === "string" ? expense.note : ""
          }));
        } catch {
          return [];
        }
      }

      function saveExpenses() {
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        } catch {
          // The tracker continues to work for the current session.
        }
      }

      function createId() {
        return Date.now().toString(36) + Math.random().toString(36).slice(2);
      }

      function formatAmount(value) {
        return Number(value).toFixed(2);
      }

      function createExpenseRow(expense) {
        const row = document.createElement("div");
        row.className = "expense";
        row.dataset.id = expense.id;
        row.dataset.category = expense.category;
        row.dataset.date = expense.date;
        row.dataset.amount = String(expense.amount);

        const amount = document.createElement("span");
        amount.className = "amount-cell";
        amount.textContent = "$" + formatAmount(expense.amount);

        const category = document.createElement("span");
        category.className = "category-cell";
        category.textContent = expense.category;

        const date = document.createElement("span");
        date.textContent = expense.date;

        const note = document.createElement("span");
        note.className = "note-cell";
        note.textContent = expense.note || "—";

        const deleteButton = document.createElement("button");
        deleteButton.type = "button";
        deleteButton.className = "exp-del";
        deleteButton.textContent = "Delete";
        deleteButton.setAttribute("aria-label", "Delete expense");

        row.append(amount, category, date, note, deleteButton);
        return row;
      }

      function renderExpenses() {
        list.textContent = "";

        for (const expense of expenses) {
          list.appendChild(createExpenseRow(expense));
        }

        applyFilters();
      }

      function applyFilters() {
        const selectedCategory = filterCategory.value;
        const fromDate = filterFrom.value;
        const toDate = filterTo.value;
        const categoryTotals = Object.fromEntries(
          categories.map(category => [category, 0])
        );

        let visibleTotal = 0;
        let visibleCount = 0;

        for (const row of list.querySelectorAll(".expense")) {
          const matchesCategory =
            selectedCategory === "all" ||
            row.dataset.category === selectedCategory;

          const matchesFrom =
            !fromDate || row.dataset.date >= fromDate;

          const matchesTo =
            !toDate || row.dataset.date <= toDate;

          const isVisible = matchesCategory && matchesFrom && matchesTo;
          row.hidden = !isVisible;

          if (isVisible) {
            const amount = Number(row.dataset.amount);
            visibleTotal += amount;
            categoryTotals[row.dataset.category] += amount;
            visibleCount++;
          }
        }

        totalElement.textContent = formatAmount(visibleTotal);

        for (const element of document.querySelectorAll(".cat-total")) {
          const category = element.dataset.cat;
          const valueElement = element.querySelector("strong");
          valueElement.textContent = formatAmount(categoryTotals[category] || 0);
        }

        emptyMessage.hidden = visibleCount !== 0;
        emptyMessage.textContent = expenses.length === 0
          ? "No expenses yet."
          : "No expenses match the current filters.";
      }

      form.addEventListener("submit", event => {
        event.preventDefault();

        const rawAmount = amountInput.value.trim();
        const amount = Number(rawAmount);
        const date = dateInput.value;

        if (
          rawAmount === "" ||
          !Number.isFinite(amount) ||
          amount <= 0
        ) {
          formError.textContent = "Enter an amount greater than zero.";
          return;
        }

        if (!date) {
          formError.textContent = "Select a date.";
          return;
        }

        expenses.unshift({
          id: createId(),
          amount,
          category: categoryInput.value,
          date,
          note: noteInput.value.trim()
        });

        saveExpenses();
        formError.textContent = "";
        amountInput.value = "";
        noteInput.value = "";
        renderExpenses();
        amountInput.focus();
      });

      list.addEventListener("click", event => {
        const deleteButton = event.target.closest(".exp-del");
        if (!deleteButton) return;

        const row = deleteButton.closest(".expense");
        expenses = expenses.filter(expense => expense.id !== row.dataset.id);
        saveExpenses();
        renderExpenses();
      });

      filterCategory.addEventListener("change", applyFilters);
      filterFrom.addEventListener("input", applyFilters);
      filterTo.addEventListener("input", applyFilters);

      renderExpenses();
    })();
  </script>
</body>
</html>
